set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<title>Welcome to Real Bank</title>

<style>
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    background: #eef3f8;
    font-family: 'Segoe UI', Arial, sans-serif;
    padding: 30px 0;
    color: #333;
}

.wrapper {
    max-width: 760px;
    margin: auto;
    background: #ffffff;
    border-radius: 20px;
    overflow: hidden;
    box-shadow: 0 15px 40px rgba(0, 0, 0, .15);
}

/* Header */
.header {
    background: linear-gradient(135deg, #002B5B, #0056B3, #0D6EFD);
    padding: 45px;
    color: #fff;
    text-align: center;
}

.logo {
    font-size: 38px;
    font-weight: bold;
    letter-spacing: 1px;
}

.tagline {
    margin-top: 8px;
    font-size: 15px;
    opacity: .9;
}

/* Hero */
.hero {
    padding: 35px;
    background: #f8fbff;
    text-align: center;
}

.hero h2 {
    color: #003366;
    margin-bottom: 12px;
    font-size: 30px;
}

.hero p {
    color: #666;
    line-height: 28px;
    font-size: 15px;
}

.success {
    margin: 25px auto;
    width: 90%;
    background: #E9F8EE;
    border-left: 6px solid #16A34A;
    padding: 18px;
    border-radius: 10px;
    font-size: 16px;
    color: #0E7C3A;
    font-weight: bold;
}

/* Account Card */
.card {
    margin: 30px;
    border-radius: 16px;
    overflow: hidden;
    border: 1px solid #dfe6ee;
}

.card-title {
    background: #003366;
    color: white;
    padding: 18px;
    font-size: 20px;
    font-weight: bold;
}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    padding: 18px;
    border-bottom: 1px solid #ececec;
}

td:first-child {
    background: #fafafa;
    font-weight: bold;
    width: 38%;
    color: #555;
}

.accno {
    font-size: 24px;
    font-weight: bold;
    color: #0056B3;
}

.balance {
    font-size: 26px;
    font-weight: bold;
    color: #16A34A;
}

.active {
    background: #DDF8E7;
    color: #118A43;
    padding: 6px 18px;
    border-radius: 25px;
    font-weight: bold;
}

/* Feature Cards */
.features {
    display: flex;
    gap: 18px;
    padding: 0 30px 30px;
}

.feature {
    flex: 1;
    background: #f7fbff;
    border: 1px solid #dbeafe;
    padding: 22px;
    border-radius: 15px;
    text-align: center;
}

.feature .icon {
    font-size: 40px;
}

.feature h3 {
    margin: 15px 0;
    color: #003366;
}

.feature p {
    font-size: 13px;
    line-height: 22px;
    color: #666;
}

/* Security */
.security {
    margin: 0 30px 30px;
    background: #FFF8EA;
    padding: 22px;
    border-left: 6px solid orange;
    border-radius: 10px;
}

.security h3 {
    margin-bottom: 12px;
    color: #C97B00;
}

.security li {
    margin: 10px 0;
}

/* Footer */
.footer {
    background: #002B5B;
    padding: 35px;
    text-align: center;
    color: white;
}

.footer h3 {
    margin-bottom: 10px;
}

.footer p {
    line-height: 24px;
    font-size: 13px;
    opacity: .95;
}

.support {
    margin-top: 20px;
    padding-top: 20px;
    border-top: 1px solid rgba(255, 255, 255, .2);
}
</style>

</head>

<body>

<div class='wrapper'>

<div class='header'>

<div class='logo'>

🏦 " ++ (vars.inputAttributes.bankName default "REAL BANK") ++ "

</div>

<div class='tagline'>

Safe • Secure • Trusted Banking

</div>

</div>

<div class='hero'>

<h2>

Welcome,
" ++ upper(vars.inputPayload.FullName default "CUSTOMER") ++ " 👋

</h2>

<p>

Thank you for choosing
<b>" ++ (vars.inputAttributes.bankName default "Real Bank") ++ "</b>.

Your account has been successfully created and is now ready for banking.

</p>

<div class='success'>

✅ Account Created Successfully

</div>

</div>

<div class='card'>

<div class='card-title'>

💳 Account Summary

</div>

<table>

<tr>
<td>👤 Customer Name</td>
<td>" ++ (vars.inputPayload.FullName default "") ++ "</td>
</tr>

<tr>
<td>🏦 Bank Name</td>
<td>" ++ (vars.inputAttributes.bankName default "") ++ "</td>
</tr>

<tr>
<td>🔖 IFSC Code</td>
<td>" ++ (vars.ifsc default "") ++ "</td>
</tr>

<tr>
<td>🏢 Branch Name</td>
<td>" ++ (vars.branchName default "") ++ "</td>
</tr>

<tr>
<td>💳 Account Number</td>
<td class='accno'>" ++ (vars.accountNumber default "") ++ "</td>
</tr>

<tr>
<td>📱 Mobile Number</td>
<td>" ++ (vars.inputPayload.mobileNumber default "") ++ "</td>
</tr>

<tr>
<td>📧 Email Address</td>
<td>" ++ (vars.inputPayload.email default "") ++ "</td>
</tr>

<tr>
<td>🪪 Aadhaar Number</td>
<td>XXXX XXXX " ++ (((vars.inputAttributes.adharNumber default "") as String)[-4 to -1]) ++ "</td>
</tr>

<tr>
<td>📍 Address</td>
<td>" ++ (vars.inputPayload.address default "") ++ "</td>
</tr>

<tr>
<td>💰 Opening Balance</td>
<td class='balance'>₹0.00</td>
</tr>

<tr>
<td>✅ Account Status</td>
<td><span class='active'>ACTIVE</span></td>
</tr>

</table>

</div>

<div class='features'>

<div class='feature'>

<div class='icon'>📱</div>

<h3>Mobile Banking</h3>

<p>

Transfer funds instantly.

UPI Payments.

Bill Payments.

Recharge Services.

</p>

</div>

<div class='feature'>

<div class='icon'>🌐</div>

<h3>Internet Banking</h3>

<p>

Mini Statement.

Download Statements.

Manage Beneficiaries.

Profile Updates.

</p>

</div>

<div class='feature'>

<div class='icon'>💳</div>

<h3>Debit Card</h3>

<p>

Card Controls.

ATM Withdrawals.

Contactless Payments.

Transaction Limits.

</p>

</div>

</div>

<div class='security'>

<h3>

🔐 Important Security Guidelines

</h3>

<ul>

<li>Never share your OTP, ATM PIN or CVV.</li>

<li>Real Bank never asks for passwords or OTP over phone.</li>

<li>Always verify beneficiaries before fund transfer.</li>

<li>Enable SMS & Email transaction alerts.</li>

<li>Report unauthorized activity immediately.</li>

</ul>

</div>

<div class='footer'>

<h3>

Thank You For Banking With Us ❤️

</h3>

<p>

Customer Care : +91 9494207062

<br>

Email : narsingbeesetti22@gmail.com

<br><br>

© 2026 Real Bank

<br>

Safe Banking | Digital Banking | Secure Transactions

</p>

<div class='support'>

This is an automated email. Please do not reply.

</div>

</div>

</div>

</body>
</html>"]
